from datetime import datetime from uuid import UUID from pydantic import BaseModel, EmailStr, Field, ConfigDict
class UserBase(BaseModel): email: EmailStr name: str = Field(..., min_length=1, max_length=100)
class UserCreate(UserBase): password: str = Field(..., min_length=8, max_length=100)
class UserUpdate(BaseModel): email: EmailStr | None = None name: str | None = Field(None, min_length=1, max_length=100)
class UserResponse(UserBase): model_config = ConfigDict(from_attributes=True) id: UUID is_active: bool created_at: datetime
